import{_ as a,c as s,o as p,ag as i}from"./chunks/framework.ELrfyV9R.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2026-01/2026-01-25-skill.md","filePath":"ai/2026-01/2026-01-25-skill.md","lastUpdated":1774447093000}'),t={name:"ai/2026-01/2026-01-25-skill.md"};function l(n,e,o,d,r,c){return p(),s("div",null,e[0]||(e[0]=[i('<p>![[Pasted image 20260125235748.png]]</p><p>因为我已经使用Codex生成过一次视频了，本文主要是想用国产的OpenCode工具，以及国产的大模型GLM-4.7 来看看他们配合的能力如何，没想到效果还是超出了我的预期，使用起来非常简单，全程都是跟OpenCode进行对话。没有一点夸张，请划到文末看我最后生成的视频。 接下来就先进行准备工作</p><h2 id="准备图片视频的-skill" tabindex="-1">准备图片视频的 Skill <a class="header-anchor" href="#准备图片视频的-skill" aria-label="Permalink to &quot;准备图片视频的 Skill&quot;">​</a></h2><p>这是github上开源的可以直接下载放到skills文件夹下即可，我下面有操作怎么下载。 <a href="https://github.com/yizhiyanhua-ai/media-downloader" target="_blank" rel="noreferrer">https://github.com/yizhiyanhua-ai/media-downloader</a></p><p>![[Pasted image 20260125134911.png]]</p><p>如果你不知道怎么下载也可以直接丢给OpenCode、Claude Code 、Codex 、Cursor等工具，它会直接把这个skill给你下载下来。下面我的提示词</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://github.com/yizhiyanhua-ai/media-downloader 给我把这个代码仓库下载下来，它是一个skill,帮我放到对应的文件夹中</span></span></code></pre></div><p>看下面截图已经到了我的Skills文件夹下了</p><p>![[Pasted image 20260125140044.png]]</p><p>第一个skill准备完毕</p><h2 id="准备第二个skill" tabindex="-1">准备第二个skill <a class="header-anchor" href="#准备第二个skill" aria-label="Permalink to &quot;准备第二个skill&quot;">​</a></h2><p>直接打开链接 <a href="https://skills.sh/remotion-dev/skills/remotion-best-practices" target="_blank" rel="noreferrer">https://skills.sh/remotion-dev/skills/remotion-best-practices</a> ![[Pasted image 20260125140253.png]]</p><p>看我的箭头复制这个命令,还是交给OpenCode给我安装</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx skills add https://github.com/remotion-dev/skills --skill remotion-best-practices 帮我执行这个命令 安装这个skill</span></span></code></pre></div><p>![[Pasted image 20260125140703.png]]</p><h2 id="准备完毕-开始出片" tabindex="-1">准备完毕，开始出片 <a class="header-anchor" href="#准备完毕-开始出片" aria-label="Permalink to &quot;准备完毕，开始出片&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>通过 media-downloader 下载一些基努里维斯的电影片段并使用remotion-best-practices（生成的项目就放在本工作区）剪辑成一个高燃的短视频。</span></span></code></pre></div><p>![[Pasted image 20260125222855.png]]</p><p>我一般喜欢点支烟静静的看OpenCode到底在干什么，有时候看他一只报错我就会停下来告诉他。其实我什么也没说，就说报错了你看看怎么处理。</p><p>![[Pasted image 20260125223357.png]]</p><p>它现解决了这个错误，然后继续它之前规划的任务了。</p><p>![[Pasted image 20260125223453.png]]</p><p>两个时间段第一个接近8分钟，第二个接近19分钟，总共27分钟。 好了来看视频效果吧。</p><p>![[Pasted image 20260125223748.png]]</p><p>我应该让他找高清视频的。也就是要找好的素材。</p><p>![[Pasted image 20260125224132.png]]</p><p>我当时应该限制一下片段个数和时间长度。不过也没关系。这里的字幕解决其实就是示意一下，然后我们根据场景去修改文字就可以了。比如第一个场景的字幕我把它改成：wocao，开场就震撼，这后期还了得。</p><p>![[Pasted image 20260125225036.png]]</p><p>我继续让他加点东西，左上角主角标识，左下角第几个片段标识，每个片段切换时的动画效果 其实并不好看，也不炫酷，主要是来看能不能操作。</p><p>给字幕配个音吧，其实这里我应该部署一下qwen3-tts，可以定制设计声音，不过本地都还没部署，等有空了继续进行尝试吧。</p><p>![[Pasted image 20260125231105.png]]</p><p>后期就是针对每个地方进行优化打磨，其实就这么简单 so easy。但是想要做一个好的剪辑视频出来也不是那么容易的，还是有很多的细节去研究。</p><p>好了今天的分享就到这里，希望我的分享对你有帮助。</p>',33)]))}const m=a(t,[["render",l]]);export{g as __pageData,m as default};
